import { Injectable, BadRequestException } from '@nestjs/common';
import { GoogleGenAI, Type } from '@google/genai';
import * as ffmpeg from 'fluent-ffmpeg';
import * as ffmpegInstaller from '@ffmpeg-installer/ffmpeg';
import * as path from 'path';
import * as fs from 'fs';
import * as os from 'os';

// Configurar ffmpeg con el binario embebido
ffmpeg.setFfmpegPath(ffmpegInstaller.path);

@Injectable()
export class AnalyzeTechniqueUseCase {
    private readonly ai: GoogleGenAI;

    constructor() {
        this.ai = new GoogleGenAI({
            apiKey: process.env.GEMINI_API_KEY,
        });
    }

    // eslint-disable-next-line max-lines-per-function
    async execute(file: Express.Multer.File, exerciseName?: string) {
        if (!file) {
            throw new BadRequestException('Se requiere archivo multimedia (imagen o video)');
        }

        if (!process.env.GEMINI_API_KEY) {
            throw new BadRequestException('API Key de Gemini no configurada');
        }

        const { mimeType, contentBase64 } = await this.prepareMedia(file);

        const prompt = this.buildPrompt(exerciseName);

        const response = await this.ai.models.generateContent({
            model: 'gemini-1.5-flash',
            contents: [
                {
                    role: 'user',
                    parts: [
                        { text: prompt },
                        {
                            inlineData: {
                                data: contentBase64,
                                mimeType,
                            },
                        },
                    ],
                },
            ],
            config: {
                responseMimeType: 'application/json',
                responseSchema: this.getSchema(),
            },
        });

        try {
            if (response.text) {
                return JSON.parse(response.text);
            }
            throw new Error('Sin respuesta');
        } catch (error) {
            throw new BadRequestException('Error al parsear JSON del modelo evaluador', {
                cause: error,
            });
        }
    }

    private async prepareMedia(
        file: Express.Multer.File,
    ): Promise<{ mimeType: string; contentBase64: string }> {
        const isVideo = file.mimetype.startsWith('video/');

        if (!isVideo) {
            // Es imagen, la enviamos directamente
            return {
                mimeType: file.mimetype,
                contentBase64: file.buffer.toString('base64'),
            };
        }

        // Es video, extraemos el clip condensado para no colapsar la IA ni exceder l├¡mites
        return this.compressVideo(file);
    }

    private compressVideo(
        file: Express.Multer.File,
    ): Promise<{ mimeType: string; contentBase64: string }> {
        return new Promise((resolve, reject) => {
            const tempInput = path.join(os.tmpdir(), `eval_in_${Date.now()}.mp4`);
            const tempOutput = path.join(os.tmpdir(), `eval_out_${Date.now()}.mp4`);

            fs.writeFileSync(tempInput, file.buffer);

            ffmpeg(tempInput)
                .duration(10) // Tomar m├íximo los primeros 10 segundos
                .fps(10) // Reducir a 10 fps (suficiente para an├ílisis biomec├ínico r├ípido)
                .size('?x480') // Reducir alto para ahorrar tokens
                .output(tempOutput)
                .on('end', () => {
                    const outBuffer = fs.readFileSync(tempOutput);
                    fs.unlinkSync(tempInput);
                    fs.unlinkSync(tempOutput);
                    resolve({
                        mimeType: 'video/mp4',
                        contentBase64: outBuffer.toString('base64'),
                    });
                })
                .on('error', (err: Error) => {
                    if (fs.existsSync(tempInput)) fs.unlinkSync(tempInput);
                    if (fs.existsSync(tempOutput)) fs.unlinkSync(tempOutput);
                    reject(new BadRequestException(`Error procesando video: ${err.message}`));
                })
                .run();
        });
    }

    // eslint-disable-next-line max-lines-per-function
    private buildPrompt(exerciseName?: string): string {
        const defaultText = `Act├║a como un preparador f├¡sico experto. ` +
            `Analiza este contenido multimedia del usuario realizando un ejercicio y devuelve ` +
            `exclusivamente un objeto JSON que eval├║e la postura bas├índote en est├índares de seguridad biomec├ínica.`;
        if (exerciseName) {
            return `${defaultText} El ejercicio que se est├í intentando ejecutar es: "${exerciseName}".`;
        }
        return defaultText;
    }

    // eslint-disable-next-line max-lines-per-function
    private getSchema() {
        return {
            type: Type.OBJECT,
            properties: {
                ejercicio: { type: Type.STRING },
                fase_movimiento: { type: Type.STRING },
                analisis_puntos_clave: {
                    type: Type.OBJECT,
                    properties: {
                        espalda: { type: Type.STRING },
                        rango_movimiento: { type: Type.STRING },
                        alineacion_articulaciones: { type: Type.STRING },
                    },
                },
                errores_detectados: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING },
                },
                correccion_inmediata: { type: Type.STRING },
                score_seguridad: { type: Type.INTEGER },
            },
            required: [
                'ejercicio',
                'fase_movimiento',
                'analisis_puntos_clave',
                'errores_detectados',
                'correccion_inmediata',
                'score_seguridad',
            ],
        };
    }
}

import { Prisma } from '@prisma/client';
import type { SessionInstance } from '../../domain/session.entity';

export function mapSession(
  row: Prisma.SessionInstanceGetPayload<{ include: ReturnType<typeof sessionInclude> }>,
): SessionInstance {
  return {
    clientId: row.clientId,
    finishComment: row.finishComment,
    finishedAt: row.finishedAt,
    id: row.id,
    isCompleted: row.isCompleted,
    isIncomplete: row.isIncomplete,
    items: row.items.map((item) => ({
      displayName: item.displayName,
      id: item.id,
      logs: item.logs.map((L) => ({
        effortRpe: L.effortRpe,
        repsDone: L.repsDone,
        sessionItemId: L.sessionItemId,
        setIndex: L.setIndex,
        weightDoneKg: typeof L.weightDoneKg === 'number' ? L.weightDoneKg : Number(L.weightDoneKg),
      })),
      repsMax: item.repsMax,
      repsMin: item.repsMin,
      setsPlanned: item.setsPlanned,
      sortOrder: item.sortOrder,
    })),
    sessionDate: row.sessionDate,
    startedAt: row.startedAt,
    status: row.status,
    templateId: row.sourceTemplateId,
    templateVersion: row.sourceTemplateVersion,
  };
}

export function normalizeText(value: null | string | undefined): null | string {
  const normalized = value?.trim();
  return normalized ? normalized : null;
}

export function sessionInclude() {
  return {
    items: {
      orderBy: { sortOrder: 'asc' as const },
      where: { archivedAt: null },
      include: {
        logs: {
          orderBy: { setIndex: 'asc' as const },
        },
      },
    },
  };
}

export function toDecimal(value: null | number | undefined) {
  return typeof value === 'number' ? new Prisma.Decimal(value) : null;
}
